     // Verify each staked UTXO exists and is owned by pubkey
     // Verify total_staked matches sum of staked UTXO values
     // Write-once (or mutable with version for re-staking)
   };

   export const withdrawValidator: ValidationFn = async ({ uri, value, read, message }) => {
     // Parse URI: gas://withdraw/{pubkey}/{withdrawId}
     // Verify staking record exists
     // Verify cooldown period elapsed
     // Verify no pending slashing
   };

